func NewSsoRoleMatchingValue(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) (SsoRoleMatchingValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	// Reference: https://github.com/hashicorp/terraform-plugin-framework/issues/521
	ctx := context.Background()

	for name, attributeType := range attributeTypes {
		attribute, ok := attributes[name]

		if !ok {
			diags.AddError(
				"Missing SsoRoleMatchingValue Attribute Value",
				"While creating a SsoRoleMatchingValue value, a missing attribute value was detected. "+
					"A SsoRoleMatchingValue must contain values for all attributes, even if null or unknown. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("SsoRoleMatchingValue Attribute Name (%s) Expected Type: %s", name, attributeType.String()),
			)

			continue
		}

		if !attributeType.Equal(attribute.Type(ctx)) {
			diags.AddError(
				"Invalid SsoRoleMatchingValue Attribute Type",
				"While creating a SsoRoleMatchingValue value, an invalid attribute value was detected. "+
					"A SsoRoleMatchingValue must use a matching attribute type for the value. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("SsoRoleMatchingValue Attribute Name (%s) Expected Type: %s\n", name, attributeType.String())+
					fmt.Sprintf("SsoRoleMatchingValue Attribute Name (%s) Given Type: %s", name, attribute.Type(ctx)),
			)
		}
	}

	for name := range attributes {
		_, ok := attributeTypes[name]

		if !ok {
			diags.AddError(
				"Extra SsoRoleMatchingValue Attribute Value",
				"While creating a SsoRoleMatchingValue value, an extra attribute value was detected. "+
					"A SsoRoleMatchingValue must not contain values beyond the expected attribute types. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("Extra SsoRoleMatchingValue Attribute Name: %s", name),
			)
		}
	}

	if diags.HasError() {
		return NewSsoRoleMatchingValueUnknown(), diags
	}

	assignedAttribute, ok := attributes["assigned"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`assigned is missing from object`)

		return NewSsoRoleMatchingValueUnknown(), diags
	}

	assignedVal, ok := assignedAttribute.(basetypes.StringValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`assigned expected to be basetypes.StringValue, was: %T`, assignedAttribute))
	}

	matchAttribute, ok := attributes["match"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`match is missing from object`)

		return NewSsoRoleMatchingValueUnknown(), diags
	}

	matchVal, ok := matchAttribute.(basetypes.StringValue)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`match expected to be basetypes.StringValue, was: %T`, matchAttribute))
	}

	if diags.HasError() {
		return NewSsoRoleMatchingValueUnknown(), diags
	}

	return SsoRoleMatchingValue{
		Assigned: assignedVal,
		Match:    matchVal,
		state:    attr.ValueStateKnown,
	}, diags
}

func NewSsoRoleMatchingValueMust(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) SsoRoleMatchingValue {
	object, diags := NewSsoRoleMatchingValue(attributeTypes, attributes)

	if diags.HasError() {
		// This could potentially be added to the diag package.
		diagsStrings := make([]string, 0, len(diags))

		for _, diagnostic := range diags {
			diagsStrings = append(diagsStrings, fmt.Sprintf(
				"%s | %s | %s",
				diagnostic.Severity(),
				diagnostic.Summary(),
				diagnostic.Detail()))
		}

		panic("NewSsoRoleMatchingValueMust received error(s): " + strings.Join(diagsStrings, "\n"))
	}

	return object
}

func (t SsoRoleMatchingType) ValueFromTerraform(ctx context.Context, in tftypes.Value) (attr.Value, error) {
	if in.Type() == nil {
		return NewSsoRoleMatchingValueNull(), nil
	}

	if !in.Type().Equal(t.TerraformType(ctx)) {
		return nil, fmt.Errorf("expected %s, got %s", t.TerraformType(ctx), in.Type())
	}

	if !in.IsKnown() {
		return NewSsoRoleMatchingValueUnknown(), nil
	}

	if in.IsNull() {
		return NewSsoRoleMatchingValueNull(), nil
	}

	attributes := map[string]attr.Value{}

	val := map[string]tftypes.Value{}

	err := in.As(&val)

	if err != nil {
		return nil, err
	}

	for k, v := range val {
		a, err := t.AttrTypes[k].ValueFromTerraform(ctx, v)

		if err != nil {
			return nil, err
		}

		attributes[k] = a
	}

	return NewSsoRoleMatchingValueMust(SsoRoleMatchingValue{}.AttributeTypes(ctx), attributes), nil
}

